import Foundation
@testable import GISTools
import Testing

/// Buffer tests.
///
/// Two groups of tests:
///
/// 1. **Reference tests** using GeoJSON files generated by `turf.js`
///    (`@turf/buffer` + `@turf/jsts`). Expected outputs are in
///    `TestData/Buffer/` and comparisons use TOTAL AREA with a 5%
///    tolerance.
///
/// 2. **Ported Turf.js buffer tests** — input + expected-output files
///    from the `@turf/buffer` test suite. Each input has
///    `properties.{radius,units}` for the buffer distance.
///    Comparisons use 10% area tolerance.
struct BufferTests {

    // MARK: - Reference test helpers

    private func loadExpected(_ name: String) throws -> MultiPolygon {
        try TestData.multiPolygon(package: "Buffer", name: name)
    }

    private func checkArea(
        _ result: MultiPolygon,
        _ expected: MultiPolygon,
        tolerance: Double = 0.05
    ) {
        let resultArea = result.polygons.reduce(0) { $0 + $1.area }
        let expectedArea = expected.polygons.reduce(0) { $0 + $1.area }
        if expectedArea == 0 {
            #expect(resultArea == 0)
            return
        }
        let ratio = resultArea / expectedArea
        #expect(ratio > 1.0 - tolerance && ratio < 1.0 + tolerance,
                "Area ratio \(ratio) outside [\(1 - tolerance), \(1 + tolerance)]")
    }

    // MARK: - Turf helper methods

    private static func expectedArea(
        _ name: String,
        tolerance: Double = 0.10
    ) throws -> (area: Double, tolerance: Double) {
        let fc = try TestData.featureCollection(package: "Buffer/out", name: name)
        var total: Double = 0
        for feature in fc.features {
            guard feature.properties["stroke"] as? String == "#F00" else { continue }
            if let polygon = feature.geometry as? Polygon {
                total += polygon.area
            }
            else if let multiPolygon = feature.geometry as? MultiPolygon {
                total += multiPolygon.polygons.reduce(0) { $0 + $1.area }
            }
        }
        return (total, tolerance)
    }

    private static func bufferParams(_ name: String) throws -> (distance: Double, steps: Int) {
        let json = try TestData.stringFromFile(package: "Buffer/in", name: name)
        guard let data = json.data(using: .utf8),
              let dict = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        else { return (GISTool.convertToMeters(50, .miles), 64) }

        let props = dict["properties"] as? [String: Any] ?? [:]
        let radius = props["radius"] as? Double ?? 50.0
        let units = props["units"] as? String ?? "miles"
        let steps = props["steps"] as? Int ?? 64

        let unit: GISTool.Unit
        switch units {
        case "meters", "metres": unit = .meters
        case "miles": unit = .miles
        default: unit = .miles
        }
        return (GISTool.convertToMeters(abs(radius), unit), steps)
    }

